commit 142035edd4b1ab431c0ecbd547d4a77f1eca0667
Author: Chris Mumford <cmumford@google.com>
Date:   Mon May 6 10:51:11 2019 -0700

    Initialize Stats::start_ before first use in Stats::Start().

    Avoids a use before initialization error. This fixes issue #676.

    PiperOrigin-RevId: 246855204

diff --git a/benchmarks/db_bench.cc b/benchmarks/db_bench.cc
index 3090b43..3696023 100644
--- a/benchmarks/db_bench.cc
+++ b/benchmarks/db_bench.cc
@@ -185,18 +185,16 @@ class Stats {
  public:
   Stats() { Start(); }

   void Start() {
     next_report_ = 100;
-    last_op_finish_ = start_;
     hist_.Clear();
     done_ = 0;
     bytes_ = 0;
     seconds_ = 0;
-    start_ = g_env->NowMicros();
-    finish_ = start_;
     message_.clear();
+    start_ = finish_ = last_op_finish_ = g_env->NowMicros();
   }

   void Merge(const Stats& other) {
     hist_.Merge(other.hist_);
     done_ += other.done_;

commit 47cb9e2a211e1d7157078ba7bab536beb29e56dc
Author: cmumford <cmumford@google.com>
Date:   Wed Oct 25 16:13:51 2017 -0700

    Add leveldb_options_set_max_file_size to the C API.

    When the max file size option was added in CL 134391640 the C API
    was not modified to support this.

    This change was contributed by GitHub user @olt and fixes issue #439.

    -------------
    Created by MOE: https://github.com/google/moe
    MOE_MIGRATED_REVID=173466388

diff --git a/db/c.cc b/db/c.cc
index 08ff0ad..d242385 100644
--- a/db/c.cc
+++ b/db/c.cc
@@ -444,10 +444,14 @@ void leveldb_options_set_block_size(leveldb_options_t* opt, size_t s) {

 void leveldb_options_set_block_restart_interval(leveldb_options_t* opt, int n) {
   opt->rep.block_restart_interval = n;
 }

+void leveldb_options_set_max_file_size(leveldb_options_t* opt, size_t s) {
+  opt->rep.max_file_size = s;
+}
+
 void leveldb_options_set_compression(leveldb_options_t* opt, int t) {
   opt->rep.compression = static_cast<CompressionType>(t);
 }

 leveldb_comparator_t* leveldb_comparator_create(
